insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0001','System Friction','origin','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["friccion_sistémica", "latencia_institucional", "entropia_acumulada"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0002", "SF_P_0003", "SF_P_0010", "SF_P_0021", "SF_P_0041"], "docRelations": ["SF_D_NODE_0001"], "docRefs": [{"doc_id": "SF_D_NODE_0001", "source": "SF_docs.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "derived", "dimension": "origin", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "System Friction es el sistema raíz del ecosistema. Proporciona el vocabulario operativo, la arquitectura conceptual y los principios para observar cómo los sistemas complejos acumulan entropía invisible bajo indicadores oficialmente estables."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0002','Campo Cognitivo','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["observacion_epistemica", "marco_logico"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0001", "SF_P_0003", "SF_P_0004", "SF_P_0021"], "docRelations": ["SF_D_NODE_0002"], "docRefs": [{"doc_id": "SF_D_NODE_0002", "source": "SF_docs.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "Campo Cognitivo es la capa puramente teórica del ecosistema. No es una marca ni producto; es la infraestructura conceptual que da coherencia al sistema de observación. Provee fundamentos filosóficos y metodológicos al marco analítico."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0003','Fricción Sistémica','theory','sfi',0.1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["señal_detectada", "respuesta_ejecutada", "latencia_institucional"], "metrics": [], "inputs": [], "outputs": [], "equations": ["FS = LDI / VR  (donde LDI=latencia decisional, VR=velocidad de respuesta)"], "relations": ["SF_P_0001", "SF_P_0004", "SF_P_0041", "SF_P_0042"], "docRelations": ["SF_D_NODE_0003"], "docRefs": [{"doc_id": "SF_D_NODE_0003", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "F_s", "formula": "(t_d/T_esp)+O", "weight": 0.1, "dimension": "structural"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "Fricción Sistémica es el concepto central del marco. Cuantifica la pérdida de señal entre la observación de una anomalía y la respuesta institucional verificable. Cuando la fricción supera la capacidad de respuesta, el colapso es matemáticamente inevitable."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0004','Interacción Humana Multicanal','theory','sfi',0.0833,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["canales_activos", "coherencia_señal", "ruido_canal"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0003", "SF_P_0005", "SF_P_0041"], "docRelations": ["SF_D_NODE_0004"], "docRefs": [{"doc_id": "SF_D_NODE_0004", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "I_mc", "formula": "1-(d_c/C_t)", "weight": 0.0833, "dimension": "relational"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Interacción Humana Multicanal reconoce que los sistemas institucionales operan con múltiples canales de señal simultáneos: formales, informales, tácitos y explícitos. La fricción emerge en los puntos de desacoplamiento entre canales."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0005','Energía Relacional','theory','sfi',0.0833,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["capacidad_vincular", "degradacion_relacional", "resiliencia_vincular"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0003", "SF_P_0006", "SF_P_0044"], "docRelations": ["SF_D_NODE_0005"], "docRefs": [{"doc_id": "SF_D_NODE_0005", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "E_r", "formula": "(C_v/T_m)*(1-D_f)", "weight": 0.0833, "dimension": "relational"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Energía Relacional mide la vitalidad de los vínculos operativos entre agentes institucionales. Su degradación es un indicador temprano de fragmentación sistémica antes de que los indicadores oficiales lo registren."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0006','Densidad de Interacción','theory','sfi',0.075,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["frecuencia_intercambio", "calidad_señal", "nodos_activos"], "metrics": [], "inputs": [], "outputs": [], "equations": ["DI = sum(interacciones_verificadas) / (nodos_activos * periodo_temporal)"], "relations": ["SF_P_0005", "SF_P_0007", "SF_P_0046"], "docRelations": ["SF_D_NODE_0006"], "docRefs": [{"doc_id": "SF_D_NODE_0006", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "D_i", "formula": "(I_t/N)/C_p", "weight": 0.075, "dimension": "temporal"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Densidad de Interacción es una métrica que cuantifica la intensidad comunicacional de un sistema. Alta densidad con baja coherencia señal es un indicador clásico de fricción sistémica activa."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0007','Gradiente de Fricción','theory','sfi',0.1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["intensidad_friccion_local", "distribucion_nodal", "tension_acumulada"], "metrics": [], "inputs": [], "outputs": [], "equations": ["GF_ij = |FS_i - FS_j| / distancia_estructural_ij"], "relations": ["SF_P_0003", "SF_P_0008", "SF_P_0057"], "docRelations": ["SF_D_NODE_0007"], "docRefs": [{"doc_id": "SF_D_NODE_0007", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "G_f", "formula": "max(|F_s_i-F_s_j|/d_ij)", "weight": 0.1, "dimension": "structural"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "El Gradiente de Fricción describe cómo la fricción no es uniforme en un sistema: se concentra en puntos específicos de la red, generando zonas de alta tensión estructural que actúan como catalizadores de colapso."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0008','Coherencia Sistémica','theory','sfi',0.1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["alineacion_objetivos", "consistencia_señal", "divergencia_declarada"], "metrics": [], "inputs": [], "outputs": [], "equations": ["CS = 1 - (divergencia_real / estado_declarado)"], "relations": ["SF_P_0007", "SF_P_0009", "SF_P_0031"], "docRelations": ["SF_D_NODE_0008"], "docRefs": [{"doc_id": "SF_D_NODE_0008", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "C_s", "formula": "1-|D_o-R_o|/max(D_o,0.01)", "weight": 0.1, "dimension": "cognitive"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Coherencia Sistémica es un indicador de la salud estructural de una institución. Su degradación no suele detectarse en los indicadores oficiales porque la institución tiene incentivos para mantener la apariencia de coherencia mientras la realidad operativa diverge."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0009','Desfase Cognitivo','theory','sfi',0.075,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["percepcion_institucional", "estado_real", "lag_temporal"], "metrics": [], "inputs": [], "outputs": [], "equations": ["DC = |t_percepcion - t_evento| * factor_semantic_drift"], "relations": ["SF_P_0008", "SF_P_0010", "SF_P_0030"], "docRelations": ["SF_D_NODE_0009"], "docRefs": [{"doc_id": "SF_D_NODE_0009", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "D_cog", "formula": "t_d/t_ref", "weight": 0.075, "dimension": "temporal"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "El Desfase Cognitivo es la brecha entre lo que una institución cree que está ocurriendo y lo que está ocurriendo. Es la fuente primaria de latencia institucional: decisiones tomadas sobre una realidad que ya no existe cuando se actúa."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0010','Resonancia Semántica','theory','sfi',0.1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["coherencia_semantica", "alineacion_terminologica", "drift_semantico"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0009", "SF_P_0011", "SF_P_0044"], "docRelations": ["SF_D_NODE_0010"], "docRefs": [{"doc_id": "SF_D_NODE_0010", "source": "SF_docs_supplement_v3.js"}], "patterns": ["umbral-dual", "decisión-emergente", "coherencia-aparente"], "mihm_v3": {"variable": "R_sem", "formula": "(T_com/T_total)*(1-D_sem)", "weight": 0.1, "dimension": "semantic"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Resonancia Semántica es crítica para la eficacia institucional. Cuando dos nodos usan los mismos términos con significados distintos, la señal se degrada sin que los agentes lo perciban. Este fenómeno es la causa más subestimada de fricción sistémica."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0011','Vector Intencional','theory','sfi',0.0833,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["intencion_declarada", "intencion_real", "alineacion_vectorial"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0010", "SF_P_0012", "SF_P_0032"], "docRelations": ["SF_D_NODE_0011"], "docRefs": [{"doc_id": "SF_D_NODE_0011", "source": "SF_docs_supplement_v3.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "V_i", "formula": "(I_r/I_d)*(1-D_i_vec)", "weight": 0.0833, "dimension": "relational"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "El Vector Intencional reconoce que los agentes institucionales operan con múltiples capas de intención: la declarada (visible en reportes), la real (que guía las decisiones) y la sistémica (que el propio agente no reconoce conscientemente). La divergencia entre estas capas produce fricción."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0012','Campo Semántico Compartido','theory','sfi',0.1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["vocabulario_compartido", "marcos_comunes", "estabilidad_semantica"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0010", "SF_P_0011", "SF_P_0034"], "docRelations": ["SF_D_NODE_0012"], "docRefs": [{"doc_id": "SF_D_NODE_0012", "source": "SF_docs_supplement_v3.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "C_sem", "formula": "V_com/V_total", "weight": 0.1, "dimension": "semantic"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "El Campo Semántico Compartido es el sustrato invisible de la coordinación institucional. Su degradación no produce conflictos abiertos sino conversaciones cada vez menos eficaces. Es uno de los primeros indicadores de fragmentación sistémica."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0013','Ruido Cognitivo','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["señal_ruido", "carga_cognitiva", "filtro_institucional"], "metrics": [], "inputs": [], "outputs": [], "equations": ["RC = señales_recibidas / señales_accionables"], "relations": ["SF_P_0012", "SF_P_0014", "SF_P_0047", "SF_P_0061"], "docRelations": ["SF_D_NODE_0013"], "docRefs": [{"doc_id": "SF_D_NODE_0013", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "El Ruido Cognitivo no es la ausencia de información sino su exceso no filtrado. Los sistemas modernos generan más señal de la que pueden procesar coherentemente, y el ruido se acumula como costo cognitivo que degrada la calidad de las decisiones."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0014','Latencia Conversacional','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["t_emision", "t_recepcion", "t_procesamiento", "umbral_latencia"], "metrics": [], "inputs": [], "outputs": [], "equations": ["LC = t_procesamiento - t_emision", "LC_critica: if LC > umbral_latencia  ?'' señal_inválida"], "relations": ["SF_P_0013", "SF_P_0015", "SF_P_0046"], "docRelations": ["SF_D_NODE_0014"], "docRefs": [{"doc_id": "SF_D_NODE_0014", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Latencia Conversacional es la dimensión temporal de la fricción sistémica. Los sistemas críticos tienen umbrales de latencia por encima de los cuales la información pierde valor operativo. Cuando la latencia supera ese umbral, la señal se convierte en ruido histórico."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0015','Divergencia de Interpretación','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["interpretacion_A", "interpretacion_B", "distancia_semantica"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0010", "SF_P_0014", "SF_P_0049"], "docRelations": ["SF_D_NODE_0015"], "docRefs": [{"doc_id": "SF_D_NODE_0015", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Divergencia de Interpretación es la forma más costosa de fricción porque no requiere conflicto abierto: los agentes actúan de buena fe sobre interpretaciones distintas del mismo acuerdo. El costo se detecta solo cuando los resultados divergen de lo acordado."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0016','Sincronización Cognitiva','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["alineacion_temporal", "coherencia_marco", "velocidad_respuesta"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0009", "SF_P_0015", "SF_P_0051"], "docRelations": ["SF_D_NODE_0016"], "docRefs": [{"doc_id": "SF_D_NODE_0016", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Sincronización Cognitiva es el opuesto de la latencia y el desfase. Es el estado de alta salud sistémica en que las señales se procesan coherentemente y las respuestas llegan antes de que el problema evolucione."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0017','Canal de Señal Social','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["fidelidad_canal", "latencia_canal", "cobertura_nodal"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0016", "SF_P_0018", "SF_P_0026"], "docRelations": ["SF_D_NODE_0017"], "docRefs": [{"doc_id": "SF_D_NODE_0017", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "Los Canales de Señal Social son la infraestructura de la coordinación institucional. Su degradación produce pérdida de información crítica aunque los canales formales sigan activos. Los sistemas de fricción alta típicamente tienen canales formales intactos y canales reales degradados."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0018','Fricción Adaptativa','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["friccion_reguladora", "velocidad_cambio", "estabilidad_respuesta"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0003", "SF_P_0019", "SF_P_0052"], "docRelations": ["SF_D_NODE_0018"], "docRefs": [{"doc_id": "SF_D_NODE_0018", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "No toda fricción es destructiva. La Fricción Adaptativa es la resistencia que permite al sistema evaluar señales antes de responder impulsivamente. Su eliminación total produce inestabilidad. Su exceso produce parálisis. El modelo MIHM busca el punto de fricción óptima."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0019','Memoria Sistémica','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["retencion_historica", "acceso_operativo", "decaimiento_memoria"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0009", "SF_P_0018", "SF_P_0050"], "docRelations": ["SF_D_NODE_0019"], "docRefs": [{"doc_id": "SF_D_NODE_0019", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "La Memoria Sistémica no es el archivo: es la capacidad de usar la historia para informar decisiones presentes. Su pérdida produce que los sistemas cometan los mismos errores sistemáticamente porque no tienen acceso a los patrones que ya enfrentaron."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0020','Equilibrio Relacional','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["estabilidad_vincular", "costo_mantenimiento", "capacidad_resolucion"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0005", "SF_P_0019", "SF_P_0037", "SF_P_0055"], "docRelations": ["SF_D_NODE_0020"], "docRefs": [{"doc_id": "SF_D_NODE_0020", "source": "SF_docs.js"}], "patterns": ["señal-ruido", "latencia-politica", "contexto-perdido"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 0, "base_angle": 0, "description": "Conceptos fundacionales del sistema"}, "description": "El Equilibrio Relacional no es armonía; es estabilidad funcional. Un sistema puede tener conflictos activos y mantener equilibrio relacional si los conflictos tienen canales de resolución operativos. El desequilibrio destructivo ocurre cuando los conflictos bloquean la coordinación."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0021','Marco Teórico System Friction','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": [], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0001", "SF_P_0022", "SF_P_0041"], "docRelations": ["SF_D_NODE_0021"], "docRefs": [{"doc_id": "SF_D_NODE_0021", "source": "SF_docs.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Marco Teórico de System Friction integra conceptos de teoría de sistemas, entropía de Shannon, Ley de Goodhart y latencia institucional en un esquema coherente de observación y diagnóstico de sistemas complejos."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0022','Teoría de Campos Cognitivos','theory','sfi',0.1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["densidad_campo", "gradiente_cognitivo", "perturbacion_campo"], "metrics": [], "inputs": [], "outputs": [], "equations": [" ^?² ? = ρ_cognitiva (analogía con ecuación de Poisson)"], "relations": ["SF_P_0021", "SF_P_0023", "SF_P_0043"], "docRelations": ["SF_D_NODE_0022"], "docRefs": [{"doc_id": "SF_D_NODE_0022", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "Phi", "formula": "sum(w_i*K(x,x_i))", "weight": 0.1, "dimension": "cognitive"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Teoría de Campos Cognitivos propone que el conocimiento institucional no es discreto sino continuo: forma campos con gradientes, zonas de alta densidad (expertise concentrado) y zonas de baja densidad (vacíos de conocimiento operativo)."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0023','Dinámica de Interacciones Humanas','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["patron_interaccion", "trayectoria_dinamica", "atractor_sistemico"], "metrics": [], "inputs": [], "outputs": [], "equations": ["dX/dt = F(X, friccion, t)"], "relations": ["SF_P_0022", "SF_P_0024", "SF_P_0033"], "docRelations": ["SF_D_NODE_0023"], "docRefs": [{"doc_id": "SF_D_NODE_0023", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Dinámica de Interacciones Humanas reconoce que los sistemas institucionales son sistemas dinámicos con atractores, bifurcaciones y comportamiento caótico bajo ciertas condiciones de fricción. Su análisis permite anticipar transiciones críticas."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0024','Modelo de Energía Relacional','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["energia_total", "distribucion_nodal", "tasa_consumo"], "metrics": [], "inputs": [], "outputs": [], "equations": ["E_total = sum(E_ij) para todos los vínculos activos"], "relations": ["SF_P_0005", "SF_P_0023", "SF_P_0048"], "docRelations": ["SF_D_NODE_0024"], "docRefs": [{"doc_id": "SF_D_NODE_0024", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo de Energía Relacional formaliza la intuición de que las instituciones tienen recursos limitados para mantener relaciones. La distribución de esa energía entre nodos determina qué vínculos sobreviven bajo estrés y cuáles colapsan primero."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0025','Topología de Sistemas Sociales','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["grado_nodal", "centralidad", "clustering_coefficient"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0024", "SF_P_0026", "SF_P_0063"], "docRelations": ["SF_D_NODE_0025"], "docRefs": [{"doc_id": "SF_D_NODE_0025", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Topología de Sistemas Sociales proporciona el mapa estructural sobre el que se calculan todas las métricas MIHM. La misma fricción tiene efectos distintos según la posición topológica del nodo afectado: no es lo mismo que falle un nodo periférico que un nodo articulador."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0026','Arquitectura de Señal Humana','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["canales_activos", "fidelidad", "cobertura", "puntos_fallo"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0017", "SF_P_0025", "SF_P_0035"], "docRelations": ["SF_D_NODE_0026"], "docRefs": [{"doc_id": "SF_D_NODE_0026", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Arquitectura de Señal Humana formaliza la descripción de cómo circula la información en una institución: qué canales existen, cuáles son formales, cuáles son reales, dónde se producen pérdidas y dónde se introduce ruido."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0027','Modelo de Ruido Social','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["tipo_ruido", "intensidad", "fuente_estructural"], "metrics": [], "inputs": [], "outputs": [], "equations": ["SNR = Potencia_señal / Potencia_ruido"], "relations": ["SF_P_0013", "SF_P_0026", "SF_P_0058"], "docRelations": ["SF_D_NODE_0027"], "docRefs": [{"doc_id": "SF_D_NODE_0027", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo de Ruido Social categoriza los tipos de interferencia que degradan la señal institucional: ruido estructural (producido por la arquitectura), ruido motivacional (producido por incentivos), ruido semántico (producido por divergencia de marcos) y ruido de latencia (producido por el tiempo)."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0028','Principio de Fricción Cognitiva','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": [], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0003", "SF_P_0021", "SF_P_0036"], "docRelations": ["SF_D_NODE_0028"], "docRefs": [{"doc_id": "SF_D_NODE_0028", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Principio de Fricción Cognitiva establece que la fricción es una propiedad emergente del sistema, no una característica individual de sus agentes. Por tanto, las intervenciones efectivas son sistémicas, no personales."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0029','Teoría de Resonancia Social','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["frecuencia_patron", "amplitud", "condicion_resonancia"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0010", "SF_P_0028", "SF_P_0044"], "docRelations": ["SF_D_NODE_0029"], "docRefs": [{"doc_id": "SF_D_NODE_0029", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Teoría de Resonancia Social describe cómo ciertos patrones de comportamiento se amplifican a través del sistema cuando encuentran condiciones estructurales favorables, análogamente a la resonancia en sistemas físicos."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0030','Teoría de Desfase Conversacional','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["t_evento", "t_registro", "t_decision", "drift_informacional"], "metrics": [], "inputs": [], "outputs": [], "equations": ["Desfase = (t_decision - t_evento) * tasa_degradacion"], "relations": ["SF_P_0009", "SF_P_0029", "SF_P_0046"], "docRelations": ["SF_D_NODE_0030"], "docRefs": [{"doc_id": "SF_D_NODE_0030", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Teoría de Desfase Conversacional formaliza el patrón descrito en doc-07 (Contexto perdido): la información pierde precisión con el tiempo, y las decisiones tomadas sobre información desfasada acumulan error sistemático."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0031','Modelo de Coherencia de Grupo','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["coherencia_declarada", "coherencia_operativa", "brecha_coherencia"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0008", "SF_P_0030", "SF_P_0032"], "docRelations": ["SF_D_NODE_0031"], "docRefs": [{"doc_id": "SF_D_NODE_0031", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo de Coherencia de Grupo distingue entre la coherencia declarada (el equipo dice estar alineado) y la coherencia operativa (el equipo actúa alineado). La brecha entre ambas es un predictor temprano de disfunción."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0032','Modelo de Alineación Intencional','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["intencion_declarada", "intencion_real", "objetivo_institucional"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0011", "SF_P_0031", "SF_P_0036"], "docRelations": ["SF_D_NODE_0032"], "docRefs": [{"doc_id": "SF_D_NODE_0032", "source": "SF_docs.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo de Alineación Intencional distingue entre la alineación nominal (todos dicen querer lo mismo) y la alineación operativa (todos actúan hacia lo mismo). La delineación de esta diferencia es esencial para el diagnóstico de fricción."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0033','Teoría de Sistemas Conversacionales','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["estado_conversacional", "transicion", "patron_recurrente"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0023", "SF_P_0032", "SF_P_0066"], "docRelations": ["SF_D_NODE_0033"], "docRefs": [{"doc_id": "SF_D_NODE_0033", "source": "SF_docs.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Teoría de Sistemas Conversacionales reconoce que una conversación institucional no es solo un intercambio de información: es un sistema dinámico con sus propios atractores, resistencias y potencial de cambio de estado."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0034','Modelo de Campo Semántico','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["densidad_semantica", "ambiguedad_local", "estabilidad_semantica"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0012", "SF_P_0033", "SF_P_0043"], "docRelations": ["SF_D_NODE_0034"], "docRefs": [{"doc_id": "SF_D_NODE_0034", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo de Campo Semántico formaliza cómo el significado se distribuye en una institución: hay zonas de alta densidad semántica (términos bien definidos y compartidos) y zonas de baja densidad (términos ambiguos o disputados). La fricción aumenta en las zonas de baja densidad."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0035','Arquitectura de Interacción','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["estructura_canales", "protocolos_interaccion", "puntos_articulacion"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0026", "SF_P_0034", "SF_P_0062"], "docRelations": ["SF_D_NODE_0035"], "docRefs": [{"doc_id": "SF_D_NODE_0035", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Arquitectura de Interacción describe el diseño (implícito o explícito) de cómo un sistema organiza sus interacciones. Una arquitectura bien diseñada reduce la fricción estructural; una arquitectura disfuncional la genera sistemáticamente."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0036','Modelo de Perturbación Cognitiva','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["intensidad_perturbacion", "propagacion", "resiliencia_cognitiva"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0028", "SF_P_0035", "SF_P_0053"], "docRelations": ["SF_D_NODE_0036"], "docRefs": [{"doc_id": "SF_D_NODE_0036", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo de Perturbación Cognitiva describe cómo los shocks externos o internos se propagan a través del campo cognitivo de una institución, generando fricción transitoria o estructural dependiendo de la resiliencia del sistema."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0037','Teoría de Equilibrio Social','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["tipo_equilibrio", "basin_atraccion", "mecanismo_retorno"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0020", "SF_P_0036", "SF_P_0055"], "docRelations": ["SF_D_NODE_0037"], "docRefs": [{"doc_id": "SF_D_NODE_0037", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Teoría de Equilibrio Social en System Friction distingue entre equilibrios estables (el sistema regresa activamente a su estado), equilibrios inestables (cualquier perturbación aleja al sistema) y equilibrios metaestables (estables localmente, inestables globalmente)."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0038','Modelo de Dinámica de Fricción','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["tasa_acumulacion", "tasa_disipacion", "distribucion_espacial"], "metrics": [], "inputs": [], "outputs": [], "equations": ["dFS/dt = acumulacion(t) - disipacion(t)"], "relations": ["SF_P_0003", "SF_P_0037", "SF_P_0060"], "docRelations": ["SF_D_NODE_0038"], "docRefs": [{"doc_id": "SF_D_NODE_0038", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo de Dinámica de Fricción describe la fricción no como un estado sino como un proceso: se acumula, se redistribuye y se libera. La liberación abrupta es el colapso; la distribución controlada es la gestión efectiva de la fricción."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0039','Teoría de Transferencia Semántica','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["fidelidad_transferencia", "variacion_semantica", "acumulacion_divergencia"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0012", "SF_P_0038", "SF_P_0050"], "docRelations": ["SF_D_NODE_0039"], "docRefs": [{"doc_id": "SF_D_NODE_0039", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "La Teoría de Transferencia Semántica reconoce que el significado no se transmite perfectamente entre agentes. Cada transferencia introduce variación. La acumulación de variación produce divergencia semántica que es fuente de fricción."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0040','Modelo Global de Interacción Humana','theory','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": [], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0021", "SF_P_0039", "SF_P_0041"], "docRelations": ["SF_D_NODE_0040"], "docRefs": [{"doc_id": "SF_D_NODE_0040", "source": "SF_docs_supplement_v3.js"}], "patterns": ["metodología", "desalineación-métricas", "proxy-objetivo"], "mihm_v3": {"variable": "derived", "dimension": "theory", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 1, "base_angle": 45, "description": "Nodo en anillo temático"}, "description": "El Modelo Global de Interacción Humana es la integración teórica de los conceptos anteriores en un marco unificado. Proporciona el fundamento teórico completo del motor MIHM."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0041','Modelo MIHM','mathematics','sfi',1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["IHG", "ICE", "CRM", "Psi", "NTI", "LDI"], "metrics": [], "inputs": [], "outputs": [], "equations": ["MIHM_score = f(IHG, ICE, CRM, Psi, NTI)", "IHG = funcion_homeostasis(variables_entrada)", "ICE = suma_ponderada(carga_ejecutiva)"], "relations": ["SF_P_0001", "SF_P_0040", "SF_P_0042", "SF_P_0062", "SF_P_0061"], "docRelations": ["SF_D_NODE_0041"], "docRefs": [{"doc_id": "SF_D_NODE_0041", "source": "SF_docs.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "IHG", "formula": "sum(w_i*X_i)-sum(w_ij*int_ij)", "weight": 1.0, "dimension": "aggregate"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "MIHM es el framework algorítmico principal diseñado para detectar, predecir y redirigir la entropía sistémica antes del punto de colapso. Integra múltiples índices (IHG, ICE, CRM, NTI) en un diagnóstico cuantitativo de salud institucional."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0042','Ecuación de Fricción Cognitiva','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["distancia_semantica", "energia_interaccion", "latencia_temporal", "nivel_ruido"], "metrics": [], "inputs": [], "outputs": [], "equations": ["FC(i,j) = d_sem(i,j) * (1 + λ_t) * N_cognitivo / E_relacional", "donde d_sem = distancia semántica", "λ_t = latencia temporal", "N_cognitivo = ruido cognitivo", "E_relacional = energía relacional"], "relations": ["SF_P_0003", "SF_P_0035", "SF_P_0041", "SF_P_0069"], "docRelations": ["SF_D_NODE_0042"], "docRefs": [{"doc_id": "SF_D_NODE_0042", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Ecuación de Fricción Cognitiva es la expresión matemática central del modelo MIHM. Traduce los conceptos de fricción sistémica en una fórmula computable que produce un valor numérico para cada par de nodos del sistema."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0043','Modelo de Campo Semántico (Matemático)','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["potencial_semantico", "gradiente_semantico", "laplaciano_semantico"], "metrics": [], "inputs": [], "outputs": [], "equations": [" ?(x) = potencial_semantico_en_nodo_x", " ^? ? = gradiente_semantico", " ^?² ? = divergencia_del_campo (positiva: fuente, negativa: sumidero)"], "relations": ["SF_P_0034", "SF_P_0042", "SF_P_0059"], "docRelations": ["SF_D_NODE_0043"], "docRefs": [{"doc_id": "SF_D_NODE_0043", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Modelo de Campo Semántico Matemático traduce la descripción conceptual del campo semántico en un objeto matemático formal: un campo escalar definido sobre el espacio de nodos del sistema, con gradientes y operadores diferenciales."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0044','Métrica de Resonancia','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["MR", "correlacion_nodal", "amplitud_compartida"], "metrics": [], "inputs": [], "outputs": [], "equations": ["MR(i,j) = correlacion(serie_i, serie_j) * amplitud_media(i,j)", "MR_sistema = max(MR_ij) para todos los pares"], "relations": ["SF_P_0029", "SF_P_0043", "SF_P_0041"], "docRelations": ["SF_D_NODE_0044"], "docRefs": [{"doc_id": "SF_D_NODE_0044", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Métrica de Resonancia (MR) detecta cuando dos o más nodos del sistema se están sincronizando de manera que sus variaciones se amplifican mutuamente. Valores altos de MR pueden indicar sincronización funcional o riesgo de cascada disfuncional."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0045','Índice de Coherencia Conversacional','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["ICC", "intercambios_alineados", "intercambios_totales"], "metrics": [], "inputs": [], "outputs": [], "equations": ["ICC = intercambios_alineados / intercambios_totales * (1 - ruido_contextual)"], "relations": ["SF_P_0008", "SF_P_0044", "SF_P_0041"], "docRelations": ["SF_D_NODE_0045"], "docRefs": [{"doc_id": "SF_D_NODE_0045", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Índice de Coherencia Conversacional (ICC) mide qué proporción de los intercambios en un sistema produce alineación semántica verificable. Es un indicador de la eficiencia conversacional del sistema."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0046','Función de Latencia Social','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["carga_comunicacional", "topologia", "estado_friccion"], "metrics": [], "inputs": [], "outputs": [], "equations": ["L(t) = L_base * (1 + α*friccion(t)) * (1 + β*carga(t)) / capacidad_procesamiento(t)"], "relations": ["SF_P_0014", "SF_P_0045", "SF_P_0041", "SF_P_0061"], "docRelations": ["SF_D_NODE_0046"], "docRefs": [{"doc_id": "SF_D_NODE_0046", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Función de Latencia Social describe la latencia no como un valor fijo sino como una función dinámica que depende del estado del sistema. Permite predecir cómo cambiará la latencia bajo diferentes condiciones."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0047','Métrica de Ruido Cognitivo','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["MRC", "señales_procesadas", "señales_accionables", "carga_cognitiva"], "metrics": [], "inputs": [], "outputs": [], "equations": ["MRC = 1 - (señales_accionables / señales_procesadas)"], "relations": ["SF_P_0013", "SF_P_0046", "SF_P_0041", "SF_P_0061"], "docRelations": ["SF_D_NODE_0047"], "docRefs": [{"doc_id": "SF_D_NODE_0047", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Métrica de Ruido Cognitivo (MRC) cuantifica qué proporción de la capacidad cognitiva del sistema se consume en procesar señales que no generan acción correcta. Es un indicador de ineficiencia sistémica."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0048','Modelo de Energía de Interacción','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["energia_disponible", "energia_consumida", "balance_energetico"], "metrics": [], "inputs": [], "outputs": [], "equations": ["E_balance(t) = E_disponible(t) - E_consumida(t)", "E_disponible(t+1) = E_balance(t) + E_recuperacion(t)"], "relations": ["SF_P_0024", "SF_P_0047", "SF_P_0041"], "docRelations": ["SF_D_NODE_0048"], "docRefs": [{"doc_id": "SF_D_NODE_0048", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Modelo de Energía de Interacción formaliza el concepto de energía relacional en términos matemáticos, permitiendo calcular el balance energético de cada interacción y la disponibilidad de energía para interacciones futuras."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0049','Métrica de Divergencia Semántica','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["MDS", "distancia_semantica", "alineacion_terminologica"], "metrics": [], "inputs": [], "outputs": [], "equations": ["MDS(i,j) = distancia_coseno(vector_semantico_i, vector_semantico_j)"], "relations": ["SF_P_0015", "SF_P_0048", "SF_P_0041"], "docRelations": ["SF_D_NODE_0049"], "docRefs": [{"doc_id": "SF_D_NODE_0049", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Métrica de Divergencia Semántica (MDS) mide qué tan diferentes son los significados que distintos nodos asignan a los términos clave del sistema. Es el cuantificador directo del fenómeno descrito en la Teoría de Transferencia Semántica."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0050','Modelo de Transferencia de Significado','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["fidelidad", "tasa_perdida", "acumulacion_variacion"], "metrics": [], "inputs": [], "outputs": [], "equations": ["S(n) = S(0) * prod(f_i) para i=1 a n transferencias", "donde f_i es la fidelidad de la i-ésima transferencia"], "relations": ["SF_P_0039", "SF_P_0049", "SF_P_0043"], "docRelations": ["SF_D_NODE_0050"], "docRefs": [{"doc_id": "SF_D_NODE_0050", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Modelo de Transferencia de Significado formaliza matemáticamente cómo el significado fluye entre nodos, incluyendo la fidelidad de la transferencia, las pérdidas y la acumulación de variación."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0051','Índice de Sincronización Cognitiva','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["ISC", "sincronizacion_temporal", "alineacion_semantica"], "metrics": [], "inputs": [], "outputs": [], "equations": ["ISC = (sincronizacion_temporal * alineacion_semantica)^0.5"], "relations": ["SF_P_0016", "SF_P_0050", "SF_P_0041"], "docRelations": ["SF_D_NODE_0051"], "docRefs": [{"doc_id": "SF_D_NODE_0051", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Índice de Sincronización Cognitiva (ISC) mide qué tan sincronizados están los ciclos de procesamiento de información y toma de decisión entre los distintos nodos del sistema. Alta sincronización indica coordinación efectiva."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0052','Métrica de Fricción Adaptativa','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["MFA", "friccion_adaptativa", "friccion_destructiva"], "metrics": [], "inputs": [], "outputs": [], "equations": ["MFA = friccion_adaptativa / friccion_total", "friccion_total = friccion_adaptativa + friccion_destructiva"], "relations": ["SF_P_0018", "SF_P_0051", "SF_P_0041"], "docRelations": ["SF_D_NODE_0052"], "docRefs": [{"doc_id": "SF_D_NODE_0052", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Métrica de Fricción Adaptativa (MFA) distingue entre la fricción que el sistema necesita para funcionar correctamente (adaptativa) y la fricción que lo degrada (destructiva). Esta distinción es clave para diseñar intervenciones correctas."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0053','Función de Perturbación Conversacional','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["intensidad_perturbacion", "tipo_perturbacion", "respuesta_sistema"], "metrics": [], "inputs": [], "outputs": [], "equations": ["R(P) = R_0 + α*P + β*P² + ... (expansión en potencias)", "para |P| < P_critica", "el sistema permanece en su atractor actual"], "relations": ["SF_P_0036", "SF_P_0052", "SF_P_0041"], "docRelations": ["SF_D_NODE_0053"], "docRefs": [{"doc_id": "SF_D_NODE_0053", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Función de Perturbación Conversacional describe cómo el estado de un sistema de comunicación institucional cambia ante perturbaciones, permitiendo calcular el umbral de perturbaciones que el sistema puede absorber sin cambio de estado."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0054','Métrica de Densidad de Interacción','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["MDI", "interacciones_periodo", "nodos_activos", "capacidad_procesamiento"], "metrics": [], "inputs": [], "outputs": [], "equations": ["MDI = interacciones_verificadas / (nodos_activos * periodo * capacidad_procesamiento)"], "relations": ["SF_P_0006", "SF_P_0053", "SF_P_0041"], "docRelations": ["SF_D_NODE_0054"], "docRefs": [{"doc_id": "SF_D_NODE_0054", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Métrica de Densidad de Interacción (MDI) cuantifica la intensidad comunicacional del sistema. Se diferencia del mero conteo de interacciones al normalizar por la capacidad de procesamiento del sistema."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0055','Modelo de Estabilidad Relacional','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["energia_vinculo", "redundancia", "resistencia_perturbacion"], "metrics": [], "inputs": [], "outputs": [], "equations": ["E_estabilidad(i,j) = E_relacional(i,j) / perturbacion_esperada(i,j)"], "relations": ["SF_P_0020", "SF_P_0054", "SF_P_0041"], "docRelations": ["SF_D_NODE_0055"], "docRefs": [{"doc_id": "SF_D_NODE_0055", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Modelo de Estabilidad Relacional formaliza qué hace que un vínculo institucional sea estable: su energía, su redundancia y su resistencia a perturbaciones. Permite predecir qué vínculos fallarán primero bajo estrés."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0056','Índice de Equilibrio Sistémico','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["IES", "distancia_equilibrio", "trayectoria_sistema"], "metrics": [], "inputs": [], "outputs": [], "equations": ["IES = 1 - (distancia_al_equilibrio / distancia_maxima_posible)", "IES = f(ISC, ICC, MFA, MDI, MRC)"], "relations": ["SF_P_0037", "SF_P_0055", "SF_P_0041"], "docRelations": ["SF_D_NODE_0056"], "docRefs": [{"doc_id": "SF_D_NODE_0056", "source": "SF_docs.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Índice de Equilibrio Sistémico (IES) es un indicador de alto nivel que integra información de múltiples métricas MIHM para producir una evaluación única de qué tan cerca está el sistema de su estado de equilibrio funcional."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0057','Modelo de Gradiente de Fricción','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["gradiente_friccion", "distribucion_espacial", "evolucion_temporal"], "metrics": [], "inputs": [], "outputs": [], "equations": ["GF(x) =  ^?FS(x) = ( ^,FS/ ^,x,  ^,FS/ ^,y)", "|GF| = magnitud del gradiente en cada punto del espacio del grafo"], "relations": ["SF_P_0007", "SF_P_0056", "SF_P_0041"], "docRelations": ["SF_D_NODE_0057"], "docRefs": [{"doc_id": "SF_D_NODE_0057", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Modelo de Gradiente de Fricción formaliza la descripción de cómo la fricción se distribuye de manera no uniforme en el grafo del sistema, con concentraciones en ciertos nodos y vínculos que actúan como puntos de falla."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0058','Métrica de Ruido Social','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["MRS", "ruido_motivacional", "ruido_cultural", "ruido_politico"], "metrics": [], "inputs": [], "outputs": [], "equations": ["MRS = (ruido_motivacional + ruido_cultural + ruido_politico) / señal_total"], "relations": ["SF_P_0027", "SF_P_0057", "SF_P_0041"], "docRelations": ["SF_D_NODE_0058"], "docRefs": [{"doc_id": "SF_D_NODE_0058", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Métrica de Ruido Social (MRS) distingue el ruido de origen social del ruido técnico. El ruido social es producido por los incentivos, las dinámicas de poder y las narrativas culturales que distorsionan las señales institucionales."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0059','Modelo de Campo Conversacional','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["flujo_conversacional", "densidad_tematica", "perturbacion_campo"], "metrics": [], "inputs": [], "outputs": [], "equations": [], "relations": ["SF_P_0043", "SF_P_0058", "SF_P_0033"], "docRelations": ["SF_D_NODE_0059"], "docRefs": [{"doc_id": "SF_D_NODE_0059", "source": "SF_docs_supplement_v3.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "El Modelo de Campo Conversacional trata las conversaciones institucionales no como eventos discretos sino como manifestaciones de un campo continuo, permitiendo análisis de tendencias, patrones y predicción de estados futuros."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0060','Ecuación Global System Friction','mathematics','sfi',1,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["IHG", "GF_promedio", "L_social", "RC", "E_relacional"], "metrics": [], "inputs": [], "outputs": [], "equations": ["IHG = integral(GF) * (1 + L_social) * (1 + MRC) / E_relacional_total", "IHG óptimo  ?^ 0 (homeostasis)", "IHG < 0: sistema en desequilibrio hacia alta fricción", "Valor actual: IHG = -0.620"], "relations": ["SF_P_0041", "SF_P_0057", "SF_P_0058", "SF_P_0047", "SF_P_0048"], "docRelations": ["SF_D_NODE_0060"], "docRefs": [{"doc_id": "SF_D_NODE_0060", "source": "SF_docs.js"}], "patterns": ["incentivo-contradictorio", "compliance-narrativo", "umbral-dual"], "mihm_v3": {"variable": "IHG_global", "formula": "IHG=integral(GF)*(1+L_social)*(1+MRC)/E_relacional", "weight": 1.0, "dimension": "aggregate"}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo temático"}, "description": "La Ecuación Global es la síntesis matemática del sistema. Integra el gradiente de fricción, la latencia social, el ruido cognitivo y la energía relacional en el IHG (Índice Homeostático Global), el indicador de resumen del estado del sistema."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
insert into public.graph_nodes (node_key,label,node_type,profile,q_n,d_n,co_n,u_n,origin,epistemic_class,confidence,payload) values ('SF_P_0061',' ndice de Densidad Cognitiva (IDC)','mathematics','sfi',0,0.0,1.0,0.0,'sf_static_dataset_v3','declared',1.0,'{"variables": ["IDC", "carga_cognitiva_entrante", "capacidad_atencional"], "metrics": [], "inputs": [], "outputs": [], "equations": ["IDC = carga_cognitiva_entrante / capacidad_atencional"], "relations": ["SF_013", "SF_041", "SF_046", "SF_047"], "docRelations": ["SF_D_NODE_0061"], "docRefs": [{"doc_id": "SF_D_NODE_0061", "source": "SF_docs.js"}], "patterns": ["alerta-ignorada", "coherencia-aparente"], "mihm_v3": {"variable": "derived", "dimension": "mathematics", "contributes_to": "IHG via pipeline", "weight": 0.0}, "position": {"x": 0.0, "y": 0.0, "z": 0, "ring": 2, "base_angle": 90, "description": "Nodo en anillo tem tico"}, "description": "El IDC ( ndice de Densidad Cognitiva) mide la relaci n entre la carga de se ales entrantes y la capacidad de procesamiento efectivo del sistema. Un IDC elevado indica que el sistema est  operando cerca o por encima de su capacidad de atenci n sostenible, lo que precede a aumentos en la latencia y el ruido cognitivo."}'::jsonb) on conflict (node_key) do update set label=excluded.label,node_type=excluded.node_type,payload=excluded.payload,updated_at=now();
